using namespace std;

class Solution {
public:
    bool isPossible(vector<int>& nums) {
        unordered_map<int, int> freq;
        for (int x : nums) {
            freq[x]++;
        }

        unordered_map<int, int> expected;

        for (int x : nums) {
            if (freq[x] == 0) continue;
            freq[x]--;

            if (expected[x] > 0) {
                expected[x]--;
                if (expected[x] == 0) {
                    expected.erase(x);
                }
                expected[x+1]++;
            } else {
                if (freq[x+1] > 0 && freq[x+2] > 0) {
                    freq[x+1]--;
                    freq[x+2]--;
                    expected[x+1]++;
                } else {
                    return false;
                }
            }
        }

        return true;
    }
};

